/**
 * @fileoverview Input component — modular entry point.
 * @module module/Input
 */

import { default as razyui } from '../../index.js';
import { StateMachine } from '../shared/StateMachine.js';
import { InputDef as DEF } from '../Input.def.js';

import { DEFAULTS, CLS } from './constants.js';
import { SM_EFFECTS, setupDOM, cleanupDOM } from './view.js';
import { bindEvents } from './events.js';
import { emitEvent } from '../shared/emitEvent.js';

/**
 * Input — text input component (JIT-compatible)
 *
 * Features:
 *   - Types: text, password, email, search, url, tel, number
 *   - Three sizes: sm, md (default), lg
 *   - Label, hint, prefix/suffix slots
 *   - Clear button
 *   - Validation states
 *   - Disabled / readonly
 *
 * @param {string|Element} selector
 * @param {object} [config]
 * @param {string} [config.preset] Id registered with `JIT.setComponentPreset('Input.'+id, …)`.
 */
const Input = class {
    #root      = null;
    #destroyed = false;
    #wrapper   = null;
    #field     = null;
    #clearBtn  = null;
    #labelEl   = null;
    #hintEl    = null;
    #sm        = null;
    #config    = {};
    #eventAC   = null;

    constructor(selector, config = {}) {
        const root = razyui(selector);

        if (!root.length) {
            console.warn('Input: element not found \u2192', selector);
            return;
        }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#init();
    }

    #init() {
        const root   = this.#root;
        const config = this.#config;

        // 1. View
        const { wrapper, field, clearBtn, labelEl, hintEl } = setupDOM(root, config);
        this.#wrapper  = wrapper;
        this.#field    = field;
        this.#clearBtn = clearBtn;
        this.#labelEl  = labelEl;
        this.#hintEl   = hintEl;

        // 2. State machine
        const sm = new StateMachine({
            initial: 'idle',
            states: {
                idle:     { on: { FOCUS: 'focused', DISABLE: 'disabled', INVALIDATE: 'invalid' } },
                focused:  { on: { BLUR: 'idle', DISABLE: 'disabled', INVALIDATE: 'invalid' } },
                disabled: { on: { ENABLE: 'idle' } },
                invalid:  { on: { FOCUS: 'focused', VALIDATE: 'idle', DISABLE: 'disabled' } },
            },
            effects: SM_EFFECTS,
        }, { root, wrapper, field });
        this.#sm = sm;

        // 3. Events
        this.#eventAC = bindEvents(field, wrapper, clearBtn, {
            onInput: config.onInput,
            onChange: config.onChange,
            onClear: config.onClear,
            onFocus: () => {
                if (this.#sm.current !== 'disabled') this.#sm.send('FOCUS');
                config.onFocus?.();
            },
            onBlur: () => {
                if (this.#sm.current === 'focused') this.#sm.send('BLUR');
                config.onBlur?.();
            },
        });

        // 4. Initial states
        if (config.disabled) sm.send('DISABLE');
        if (config.readonly) wrapper.addClass(CLS.READONLY);
    }

    // ── Public API ──

    get value() { return this.#field[0].value; }
    set value(v) {
        this.#field[0].value = v;
        emitEvent(this.#field[0], 'change', { value: v });
    }

    get disabled() { return this.#sm.current === 'disabled'; }

    setDisabled(disabled) {
        if (disabled) this.#sm.send('DISABLE');
        else if (this.#sm.current === 'disabled') this.#sm.send('ENABLE');
    }

    setInvalid(invalid, message) {
        if (invalid) {
            this.#sm.send('INVALIDATE');
            this.#wrapper[0].setAttribute('aria-invalid', 'true');
            if (message && this.#hintEl) {
                this.#hintEl[0].textContent = message;
            }
        } else {
            this.#sm.send('VALIDATE');
            this.#wrapper[0].removeAttribute('aria-invalid');
        }
    }

    focus() { this.#field[0].focus(); }
    blur()  { this.#field[0].blur(); }

    clear() { this.value = ''; }

    getControl() {
        const self = this;
        return {
            get value()       { return self.value; },
            set value(v)      { self.value = v; },
            get disabled()    { return self.#field[0].disabled; },
            set disabled(v)   { self.setDisabled(v); },
            get readonly()    { return self.#field[0].readOnly; },
            set readonly(v)   { self.#field[0].readOnly = !!v; self.#wrapper.toggleClass(CLS.READONLY, !!v); self.#wrapper[0].setAttribute('aria-readonly', String(!!v)); },
            get required()    { return self.#field[0].required; },
            set required(v)   { self.#field[0].required = !!v; self.#wrapper[0].setAttribute('aria-required', String(!!v)); },
            get placeholder() { return self.#field[0].placeholder; },
            set placeholder(v){ self.#field[0].placeholder = v ?? ''; },
            get type()        { return self.#field[0].type; },
            set type(v)       { self.#field[0].type = v ?? 'text'; },
            get name()        { return self.#field[0].name; },
            set name(v)       { self.#field[0].name = v ?? ''; },
            setDisabled:  (v) => self.setDisabled(v),
            setInvalid:   (v, m) => self.setInvalid(v, m),
            checkValidity:     () => self.#field[0].checkValidity(),
            reportValidity:    () => self.#field[0].reportValidity(),
            setCustomValidity: (m) => { self.#field[0].setCustomValidity(m || ''); self.setInvalid(!!m, m); },
            get label()       { return self.#wrapper[0].getAttribute('aria-label'); },
            set label(v)      { v ? self.#wrapper[0].setAttribute('aria-label', v) : self.#wrapper[0].removeAttribute('aria-label'); },
            get labelledby()  { return self.#wrapper[0].getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#wrapper[0].setAttribute('aria-labelledby', v) : self.#wrapper[0].removeAttribute('aria-labelledby'); },
            get describedby() { return self.#wrapper[0].getAttribute('aria-describedby'); },
            set describedby(v){ v ? self.#wrapper[0].setAttribute('aria-describedby', v) : self.#wrapper[0].removeAttribute('aria-describedby'); },
            focus:        () => self.focus(),
            blur:         () => self.blur(),
            clear:        () => self.clear(),
            destroy:      () => self.destroy(),
            get element() { return self.#wrapper[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        cleanupDOM(this.#root);
    }
};

export default Input;
