/**
 * @fileoverview Input constants — CSS classes, selectors, defaults, JIT parts.
 * @module module/Input/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:        'input-root',
    WRAPPER:     'input-wrapper',
    FIELD:       'input-field',
    LABEL:       'input-label',
    DESCRIPTION: 'input-description',
    PREFIX:      'input-prefix',
    SUFFIX:      'input-suffix',
    CLEAR:       'input-clear',
    HINT:        'input-hint',
    FOCUSED:     'is-focused',
    DISABLED:    'is-disabled',
    INVALID:     'is-invalid',
    READONLY:    'is-readonly',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    type: 'text',           // text | password | email | search | url | tel | number
    size: 'md',             // sm | md | lg
    placeholder: '',
    value: '',
    label: null,
    description: null,
    hint: null,
    disabled: false,
    readonly: false,
    required: false,
    clearable: false,
    prefix: null,           // HTML string for prefix slot
    suffix: null,           // HTML string for suffix slot
    maxlength: null,
    pattern: null,
    name: null,
    onInput: null,
    onChange: null,
    onFocus: null,
    onBlur: null,
    onClear: null,
    preset: '',
});

/** Semantic part names for JIT styling. */
export const PART = defineParts('Input', {
    ROOT        : { class: 'input-container', aliases: ['root', 'container'] },
    WRAPPER     : { class: 'input-wrapper', aliases: ['wrapper'] },
    FIELD       : { class: 'input-field', aliases: ['field', 'input'], tag: 'input' },
    LABEL       : { class: 'input-label', aliases: ['label'], tag: 'label' },
    DESCRIPTION : { class: 'input-description', aliases: ['description', 'desc'], tag: 'p' },
    PREFIX      : { class: 'input-prefix', aliases: ['prefix'], tag: 'span' },
    SUFFIX      : { class: 'input-suffix', aliases: ['suffix'], tag: 'span' },
    CLEAR       : { class: 'input-clear', aliases: ['clear'], tag: 'span' },
    HINT        : { class: 'input-hint', aliases: ['hint'], tag: 'span' },
    SM_ROOT     : { class: 'input-container-sm', aliases: ['sm'] },
    LG_ROOT     : { class: 'input-container-lg', aliases: ['lg'] },
});

PART.ROOT.jit     = 'flex flex-col w-full [font-family:var(--inp-font-stack)]';
PART.WRAPPER.jit  = 'mt-[var(--inp-label-gap)] first:mt-0 inline-flex items-center w-full bg-[var(--inp-bg)] [border:1px_solid_var(--inp-border)] rounded-[var(--inp-radius)] h-[var(--inp-h)] px-[var(--inp-px)] gap-[var(--inp-gap)] ' + TRANSITION_COLORS + ' {is-focused}:[border-color:var(--inp-focus-border)] {is-focused}:[box-shadow:0_0_0_2px_var(--inp-focus-ring)] {is-invalid}:[border-color:var(--inp-error-border)] {is-invalid}:[box-shadow:0_0_0_2px_var(--inp-error-ring)] {is-disabled}:opacity-50 {is-disabled}:cursor-not-allowed {is-readonly}:bg-[var(--inp-bg-readonly)]';
PART.FIELD.jit    = 'flex-1 min-w-0 bg-transparent [border:none] [outline:none] fg-[var(--inp-text)] text-[var(--inp-font-size)] [font-family:inherit] [placeholder:var(--inp-placeholder)] [&::placeholder]:fg-[var(--inp-placeholder)]';
PART.LABEL.jit    = 'text-[var(--inp-label-size)] font-semibold fg-[var(--inp-label-text)] select-none';
PART.DESCRIPTION.jit = 'mt-[var(--inp-desc-gap)] text-[var(--inp-desc-size)] fg-[var(--inp-desc-text)]';
PART.PREFIX.jit   = 'flex items-center shrink-0 fg-[var(--inp-placeholder)]';
PART.SUFFIX.jit   = 'flex items-center shrink-0 fg-[var(--inp-placeholder)]';
PART.CLEAR.jit    = 'flex items-center justify-center shrink-0 w-[1rem] h-[1rem] cursor-pointer fg-[var(--inp-placeholder)] hover:fg-[var(--inp-text)] ' + TRANSITION_COLORS;
PART.HINT.jit     = 'mt-[var(--inp-hint-gap)] text-[var(--inp-hint-size)] fg-[var(--inp-hint-text)] {is-invalid}:fg-[var(--inp-error-text)]';
PART.SM_ROOT.jit  = '[--inp-font-size:var(--inp-sm-font-size)] [--inp-h:var(--inp-sm-h)] [--inp-px:var(--inp-sm-px)] [--inp-label-size:var(--inp-sm-label-size)]';
PART.LG_ROOT.jit  = '[--inp-font-size:var(--inp-lg-font-size)] [--inp-h:var(--inp-lg-h)] [--inp-px:var(--inp-lg-px)] [--inp-label-size:var(--inp-lg-label-size)]';