/**
 * @fileoverview Input view — DOM setup / teardown.
 * @module module/Input/view
 */

import { CLS, PART } from './constants.js';

// ═══════════════════════════════════════
//  State Machine Effects
// ═══════════════════════════════════════

export const SM_EFFECTS = {
    idle({ wrapper }) {
        wrapper.removeClass(CLS.FOCUSED).removeClass(CLS.DISABLED).removeClass(CLS.INVALID).removeClass(CLS.READONLY);
    },
    focused({ wrapper }) {
        wrapper.addClass(CLS.FOCUSED);
    },
    'focused:exit'({ wrapper }) {
        wrapper.removeClass(CLS.FOCUSED);
    },
    disabled({ wrapper, field }) {
        wrapper.addClass(CLS.DISABLED);
        field[0].disabled = true;
        wrapper[0].setAttribute('aria-disabled', 'true');
    },
    'disabled:exit'({ wrapper, field }) {
        wrapper.removeClass(CLS.DISABLED);
        field[0].disabled = false;
        wrapper[0].removeAttribute('aria-disabled');
    },
    invalid({ wrapper }) {
        wrapper.addClass(CLS.INVALID);
    },
    'invalid:exit'({ wrapper }) {
        wrapper.removeClass(CLS.INVALID);
    },
};

// ═══════════════════════════════════════
//  DOM Setup
// ═══════════════════════════════════════

/**
 * Build the input DOM.
 *
 * @param {Elements} root
 * @param {object} config
 * @returns {{ wrapper: Elements, field: Elements, clearBtn: Elements|null, labelEl: Elements|null, hintEl: Elements|null }}
 */
export function setupDOM(root, config) {
    const { size, label, description, hint, prefix, suffix, clearable, type, placeholder, value, disabled, readonly, required, maxlength, pattern, name, preset } = config;
    const presetId = preset != null && String(preset).trim() ? String(preset).trim() : undefined;

    root.addClass('input');   // token-scoping class → .input { --inp-* } (host only)

    // Layout + container JIT live on an inner stack so <rui-input> is not an extra flex box.
    // Custom-element hosts use display:contents so parent gap/align applies to the real control tree.
    const hostEl = root[0];
    const isCustomElementHost = !!hostEl?.localName?.includes('-');
    if (isCustomElementHost) {
        hostEl.style.display = 'contents';
    }

    const stack = PART.ROOT.create(undefined, presetId);
    stack.addClass(CLS.ROOT);
    if (size === 'sm') {
        PART.SM_ROOT.apply(stack, presetId);
    } else if (size === 'lg') {
        PART.LG_ROOT.apply(stack, presetId);
    }
    root.append(stack);

    // Label
    let labelEl = null;
    if (label) {
        labelEl = PART.LABEL.create(undefined, presetId);
        labelEl.text(label);
        stack.append(labelEl);
    }

    // Description
    let descEl = null;
    if (description) {
        descEl = PART.DESCRIPTION.create(undefined, presetId);
        descEl.text(description);
        stack.append(descEl);
    }

    // Wrapper
    const wrapper = PART.WRAPPER.create(undefined, presetId);
    stack.append(wrapper);

    // Prefix
    if (prefix) {
        const $pre = PART.PREFIX.create(undefined, presetId);
        $pre[0].innerHTML = prefix;
        wrapper.append($pre);
    }

    // Input field
    const field = PART.FIELD.create({
        type,
    }, presetId);
    if (placeholder) field[0].placeholder = placeholder;
    if (value) field[0].value = value;
    if (disabled) field[0].disabled = true;
    if (readonly) field[0].readOnly = true;
    if (required) field[0].required = true;
    if (maxlength) field[0].maxLength = maxlength;
    if (pattern) field[0].pattern = pattern;
    if (name) field[0].name = name;
    wrapper.append(field);

    // Clear button
    let clearBtn = null;
    if (clearable) {
        clearBtn = PART.CLEAR.create(undefined, presetId);
        clearBtn[0].innerHTML = '&#x2715;';
        clearBtn.hide();
        wrapper.append(clearBtn);
    }

    // Suffix
    if (suffix) {
        const $suf = PART.SUFFIX.create(undefined, presetId);
        $suf[0].innerHTML = suffix;
        wrapper.append($suf);
    }

    // Hint
    let hintEl = null;
    if (hint) {
        hintEl = PART.HINT.create(undefined, presetId);
        hintEl.text(hint);
        stack.append(hintEl);
    }

    return { wrapper, field, clearBtn, labelEl, descEl, hintEl };
}

export function cleanupDOM(root) {
    const el = root[0];
    if (el) {
        el.style.display = '';
        el.innerHTML = '';
    }
    root.removeClass('input');
}
